const topic = $.input.topic;
const count = $.input.videoCount || 3;
const today = new Date().toISOString().split('T')[0];

let prompt = 'You are an expert short-form video content strategist. Generate ' + count + ' unique, viral-worthy video concepts for the topic: ' + topic + '.\n\n';
prompt += 'For each video, provide:\n';
prompt += '- A catchy title optimized for social media\n';
prompt += '- A POV-style hook (first 3 seconds)\n';
prompt += '- Scene-by-scene breakdown (3-5 scenes)\n';
prompt += '- AI image generation prompt for the key visual\n';
prompt += '- Voiceover script (30-60 seconds)\n';
prompt += '- Suggested music mood\n';
prompt += '- Platform-specific caption (TikTok/YouTube Shorts/Reels style)\n';
prompt += '- Hashtags\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "videos": [\n';
prompt += '    {\n';
prompt += '      "title": "catchy title",\n';
prompt += '      "hook": "POV opening hook",\n';
prompt += '      "scenes": [{ "sceneNum": 1, "description": "what happens", "duration": "5s" }],\n';
prompt += '      "imagePrompt": "detailed AI image generation prompt",\n';
prompt += '      "voiceoverScript": "full voiceover text",\n';
prompt += '      "musicMood": "upbeat/dramatic/calm",\n';
prompt += '      "caption": "social media caption",\n';
prompt += '      "hashtags": ["#tag1", "#tag2"]\n';
prompt += '    }\n';
prompt += '  ]\n';
prompt += '}';

return { prompt, today, topic, count };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { videos: [] }; }

const ai = $.steps.parseAI.output;
const today = $.steps.buildPrompt.output.today;
const topic = $.steps.buildPrompt.output.topic;
const videos = ai.videos || [];

const headerRow = ['Date', 'Topic', 'Title', 'Hook', 'Scenes', 'Image Prompt', 'Voiceover Script', 'Music Mood', 'Caption', 'Hashtags', 'Status'];
const rows = [headerRow];

videos.forEach(v => {
  const scenesText = (v.scenes || []).map(s => 'Scene ' + s.sceneNum + ' (' + (s.duration || '') + '): ' + s.description).join('; ');
  rows.push([
    today,
    topic,
    v.title || '',
    v.hook || '',
    scenesText,
    v.imagePrompt || '',
    v.voiceoverScript || '',
    v.musicMood || '',
    v.caption || '',
    (v.hashtags || []).join(' '),
    'Generated'
  ]);
});

return { rows, videoCount: videos.length, videos };

const videos = $.steps.prepareSheetRows.output.videos || [];
const topic = $.steps.buildPrompt.output.topic;
const today = $.steps.buildPrompt.output.today;

const embeds = [];
videos.slice(0, 3).forEach((v, i) => {
  embeds.push({
    title: 'Video ' + (i + 1) + ': ' + (v.title || 'Untitled'),
    description: '**Hook:** ' + (v.hook || '') + '\n\n**Script Preview:** ' + (v.voiceoverScript || '').slice(0, 300) + '\n\n**Caption:** ' + (v.caption || '') + '\n\n' + (v.hashtags || []).join(' '),
    color: 5814783,
    fields: [
      { name: 'Music Mood', value: v.musicMood || 'N/A', inline: true },
      { name: 'Scenes', value: String((v.scenes || []).length), inline: true }
    ],
    footer: { text: 'AI Video Generator | ' + today }
  });
});

const contentText = 'New AI Video Concepts Generated for: **' + topic + '** (' + videos.length + ' videos)';
return { content: contentText.slice(0, 2000), embeds };

const videos = $.steps.prepareSheetRows.output.videos || [];
const topic = $.steps.buildPrompt.output.topic;
const today = $.steps.buildPrompt.output.today;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Video Concepts: ' + topic, emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Videos Generated:*\n' + videos.length },
  { type: 'mrkdwn', text: '*Date:*\n' + today }
] });
blocks.push({ type: 'divider' });

videos.slice(0, 5).forEach((v, i) => {
  let text = '*' + (i + 1) + '. ' + (v.title || 'Untitled') + '*\n';
  text += 'Hook: ' + (v.hook || '') + '\n';
  text += 'Script: ' + (v.voiceoverScript || '').slice(0, 200) + '...\n';
  text += 'Music: ' + (v.musicMood || 'N/A') + ' | Scenes: ' + (v.scenes || []).length + '\n';
  text += (v.hashtags || []).join(' ');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI | One CLI | Saved to Google Sheets' }] });

const fallbackText = 'AI Video Concepts: ' + videos.length + ' videos generated for ' + topic;
return { blocks, fallbackText };
